changeSet.sql:
create table incident ( id varchar(64) primary key, tenant_id varchar(64) not null references tenant(id) on delete restrict, instance_id varchar(64) not null references process_instance(id) on delete cascade, token_id varchar(64) references execution_token(id) on delete set null, token_state_id varchar(64) references execution_token_state(id) on delete set null, job_id varchar(64) references job(id) on delete set null, type varchar(24) not null check (type in ('FAILED_JOB','ERROR_BOUNDARY','CONNECTOR_ERROR')), severity varchar(16) not null default 'ERROR' check (severity in ('INFO','WARNING','ERROR')), status varchar(16) not null default 'OPEN' check (status in ('OPEN','RESOLVED','DELETED')), message text, created_at timestamptz not null default now(), resolved_at timestamptz, resolved_by varchar(255) ); create index ix_incident_instance_status on incident(instance_id, status);
alter table execution_token add constraint fk_execution_token_incident foreign key (incident_id) references incident(id) on delete set null; alter table execution_token_state add constraint fk_execution_token_state_incident foreign key (incident_id) references incident(id) on delete set null;
create table group_entity ( id varchar(64) primary key, tenant_id varchar(64) not null references tenant(id) on delete restrict, code varchar(64) not null, name varchar(255), unique(tenant_id, code) );
create table process_authorization ( id varchar(64) primary key, tenant_id varchar(64) not null references tenant(id) on delete restrict, principal_type varchar(16) not null check (principal_type in ('USER','GROUP','ROLE')), principal_id varchar(255) not null, resource_type varchar(32) not null check (resource_type in ('PROCESS_DEFINITION','PROCESS_INSTANCE','USER_TASK')), resource_id varchar(255) not null, permission varchar(16) not null check (permission in ('READ','START','UPDATE','DELETE','CLAIM')), created_at timestamptz not null default now() ); create index ix_authorization_principal on process_authorization(tenant_id, principal_type, principal_id);
create table process_comment ( id varchar(64) primary key, instance_id varchar(64) not null references process_instance(id) on delete cascade, task_id varchar(64) references user_task(id) on delete set null, author varchar(255) not null, message text not null, created_at timestamptz not null default now() ); create index ix_process_comment_instance on process_comment(instance_id);
create table process_stats_daily ( id varchar(64) primary key, definition_id varchar(64) not null references process_definition(id) on delete cascade, stat_date date not null, started_count integer not null default 0, completed_count integer not null default 0, failed_count integer not null default 0, avg_duration_ms integer, sla_breach_count integer not null default 0, unique(definition_id, stat_date) );
create table message_correlation ( id varchar(64) primary key, instance_id varchar(64) not null references process_instance(id) on delete cascade, subscription_id varchar(64) references event_subscription(id) on delete set null, correlation_key varchar(255) not null, message_name varchar(255) not null, correlated_at timestamptz not null default now() ); create index ix_message_correlation_key on message_correlation(correlation_key, message_name);
create table timer_definition ( id varchar(64) primary key, definition_id varchar(64) not null references process_definition(id) on delete cascade, node_id varchar(255) not null, timer_type varchar(16) not null check (timer_type in ('DATE','DURATION','CYCLE')), expression text not null );

